/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Provides template rendering, recipient resolution, and delivery
 * with configurable transport (real provider or in-memory for testing).
 */

import type { NotificationPayload, NotificationType } from '../models/notification.js';
import type {
  NotificationAdapter,
  NotificationDeliveryResult,
} from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/** A rendered email ready for delivery. */
export interface RenderedEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
}

/** A sent email record with delivery metadata. */
export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
  sentAt: Date;
  notificationType: NotificationType;
}

/** Configuration for the email adapter. */
export interface EmailAdapterConfig {
  /** Default sender address. */
  defaultFrom: string;
  /** Recipient resolver — maps a recipient identifier to an email address. */
  resolveRecipient?: (recipient: string) => string | null;
  /** Transport function — called for actual delivery. Return true for success. */
  transport?: (email: RenderedEmail) => Promise<boolean>;
}

const DEFAULT_FROM = 'noreply@taskflow.example.com';

/** Built-in email templates keyed by notification type. */
const EMAIL_TEMPLATES: Record<NotificationType, {
  subject: (payload: NotificationPayload) => string;
  html: (payload: NotificationPayload) => string;
  text: (payload: NotificationPayload) => string;
}> = {
  order_confirmation: {
    subject: (p) => p.subject,
    html: (p) => [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1>Order Confirmed</h1>`,
      `<p>${escapeHtml(p.body)}</p>`,
      p.metadata?.orderId
        ? `<p><strong>Order ID:</strong> ${escapeHtml(String(p.metadata.orderId))}</p>`
        : '',
      '<p>Thank you for your purchase!</p>',
      '</div>',
    ].join('\n'),
    text: (p) => `Order Confirmed\n\n${p.body}\n\nThank you for your purchase!`,
  },
  order_status_update: {
    subject: (p) => p.subject,
    html: (p) => [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1>Order Status Update</h1>`,
      `<p>${escapeHtml(p.body)}</p>`,
      '</div>',
    ].join('\n'),
    text: (p) => `Order Status Update\n\n${p.body}`,
  },
  welcome: {
    subject: (p) => p.subject,
    html: (p) => [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1>Welcome to TaskFlow Pro!</h1>`,
      `<p>${escapeHtml(p.body)}</p>`,
      '</div>',
    ].join('\n'),
    text: (p) => `Welcome to TaskFlow Pro!\n\n${p.body}`,
  },
  account_updated: {
    subject: (p) => p.subject,
    html: (p) => [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1>Account Updated</h1>`,
      `<p>${escapeHtml(p.body)}</p>`,
      '</div>',
    ].join('\n'),
    text: (p) => `Account Updated\n\n${p.body}`,
  },
};

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];
  private config: EmailAdapterConfig;

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = {
      defaultFrom: config?.defaultFrom ?? DEFAULT_FROM,
      resolveRecipient: config?.resolveRecipient,
      transport: config?.transport,
    };
  }

  /**
   * Resolve a recipient identifier to a deliverable email address.
   * Uses the configured resolver if present, otherwise returns the raw recipient
   * if it looks like an email address.
   */
  resolveRecipient(recipient: string): string | null {
    if (this.config.resolveRecipient) {
      return this.config.resolveRecipient(recipient);
    }
    return isValidEmail(recipient) ? recipient : null;
  }

  /**
   * Render a notification payload into a full email using the template
   * for the payload's notification type.
   */
  renderTemplate(payload: NotificationPayload): RenderedEmail {
    const template = EMAIL_TEMPLATES[payload.notificationType];
    const to = this.resolveRecipient(payload.recipient) ?? payload.recipient;

    return {
      to,
      from: this.config.defaultFrom,
      subject: template.subject(payload),
      html: template.html(payload),
      text: template.text(payload),
    };
  }

  /**
   * Send an email notification.
   * Resolves the recipient, renders the template, and delivers via the
   * configured transport (or stores in-memory if no transport is set).
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    try {
      const resolvedAddress = this.resolveRecipient(payload.recipient);
      if (!resolvedAddress) {
        const msg = `Cannot resolve recipient: ${payload.recipient}`;
        this.logger.error(msg);
        return { success: false, error: msg };
      }

      const rendered = this.renderTemplate(payload);
      this.logger.info(`Sending email to ${rendered.to}: ${rendered.subject}`);

      if (this.config.transport) {
        const ok = await this.config.transport(rendered);
        if (!ok) {
          const msg = `Transport rejected email to ${rendered.to}`;
          this.logger.error(msg);
          return { success: false, error: msg };
        }
      }

      this.sentEmails.push({
        to: rendered.to,
        from: rendered.from,
        subject: rendered.subject,
        html: rendered.html,
        text: rendered.text,
        sentAt: new Date(),
        notificationType: payload.notificationType,
      });

      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
