    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'email',
    notificationType: 'order_confirmation',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('channel property', () => {
    it('should be email', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('resolveRecipient', () => {
    it('should return valid email addresses as-is', () => {
      expect(adapter.resolveRecipient('alice@example.com')).toBe('alice@example.com');
    });

    it('should return null for non-email identifiers without a resolver', () => {
      expect(adapter.resolveRecipient('user-123')).toBeNull();
    });

    it('should use custom resolver when configured', () => {
      const customAdapter = new EmailAdapter({
        resolveRecipient: (id) => (id === 'user-1' ? 'alice@example.com' : null),
      });
      expect(customAdapter.resolveRecipient('user-1')).toBe('alice@example.com');
      expect(customAdapter.resolveRecipient('user-unknown')).toBeNull();
    });
  });

  describe('renderTemplate', () => {
