  describe('send', () => {
    it('should send and record email for valid recipient', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
      expect(sent[0]?.html).toContain('Order Confirmed');
      expect(sent[0]?.notificationType).toBe('order_confirmation');
    });

    it('should fail for unresolvable recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve recipient');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should use custom transport when configured', async () => {
      const transported: string[] = [];
      const customAdapter = new EmailAdapter({
        transport: async (email) => {
          transported.push(email.to);
          return true;
        },
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(transported).toEqual(['alice@example.com']);
      expect(customAdapter.getSentEmails()).toHaveLength(1);
    });

    it('should fail when transport returns false', async () => {
      const customAdapter = new EmailAdapter({
        transport: async () => false,
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Transport rejected');
      expect(customAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should catch transport errors and return failure', async () => {
      const customAdapter = new EmailAdapter({
        transport: async () => {
          throw new Error('Connection refused');
        },
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
      expect(customAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should send multiple emails and track all', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });
  });

  describe('clearSentEmails', () => {
    it('should clear all recorded emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

